#[test]
fn focus_direction_noop() {
    let mut hub = setup();
    let before = snapshot(&hub);
    hub.focus_left();
    assert_eq!(before, snapshot(&hub));
    hub.focus_right();
    assert_eq!(before, snapshot(&hub));
    hub.focus_up();
    assert_eq!(before, snapshot(&hub));
    hub.focus_down();
    assert_eq!(before, snapshot(&hub));

    hub.insert_tiling(hub.current_workspace(), titled("w37"));
    let before = snapshot(&hub);
    hub.focus_left();
    assert_eq!(before, snapshot(&hub));
    hub.focus_right();
    assert_eq!(before, snapshot(&hub));
    hub.focus_up();
    assert_eq!(before, snapshot(&hub));
    hub.focus_down();
    assert_eq!(before, snapshot(&hub));
}
